insert into operation_log (
    id, project_id, module_name, biz_id, action, operator_id, operator_name,
    request_method, request_path, request_body, result_code, ip_address, created_at
) values (
    #{id}, #{projectId}, #{moduleName}, #{bizId}, #{action}, #{operatorId}, #{operatorName},
    #{requestMethod}, #{requestPath}, #{requestBody}, #{resultCode}, #{ipAddress}, #{createdAt}
)

mapper.select:
select id, project_id, module_name, export_format, status, file_attachment_id, requested_by, requested_at, finished_at
from export_task
where id = #{id}

select ol.id, ol.project_id, ol.module_name, ol.biz_id, ol.action, ol.operator_id, ol.operator_name,
       ol.request_method, ol.request_path, ol.result_code, ol.ip_address, ol.created_at
from operation_log ol
where 1 = 1

    and ol.project_id = #{query.projectId}


    and ol.module_name = #{query.module}


    and ol.operator_id = #{query.operatorId}


    and ol.created_at  >=  #{query.startTime}


    and ol.created_at  <=  #{query.endTime}


    and ol.module_name in

        #{module}



    and exists (
        select 1
        from sys_user_role bur
                 inner join sys_role br on br.id = bur.role_id
        where bur.user_id = ol.operator_id
          and br.role_code in ('USER', 'PROJECT_MANAGER', 'TEAM_MEMBER', 'READ_ONLY')
    )
    and not exists (
        select 1
        from sys_user_role sur
                 inner join sys_role sr on sr.id = sur.role_id
        where sur.user_id = ol.operator_id
          and sr.role_code = 'SYS_ADMIN'
    )

order by ol.created_at desc
